                if (whiteSpaceAfterColon?.text != " ") {
                    if (whiteSpaceAfterColon != null && whiteSpaceAfterColon.textContains('\n')) {
                        if (maxLineLength != MAX_LINE_LENGTH_PROPERTY_OFF) {
                            val returnType = node.nextCodeSibling()
                            if (returnType != null) {
                                val lineStartOffset =
                                    node
                                        .prevLeaf { it.textContains('\n') }
                                        ?.let { it.startOffset + it.text.lastIndexOf('\n') + 1 }
                                        ?: 0
                                val currentLineLength = (node.startOffset + node.textLength) - lineStartOffset
                                val predictedLength = currentLineLength + 1 + returnType.textLength
                                if (predictedLength > maxLineLength) {
                                    return
                                }
                            }
                        }
                    }

                    emit(node.startOffset, "Single space expected between colon and return type", true)
                    if (autoCorrect) {
                        node.upsertWhitespaceAfterMe(" ")
                    }
                }
            }
